onOptionChange:
{{
(() => {
  const idSeleccionado = select_four?.selectedOptionValue
    ? String(select_four.selectedOptionValue).trim()
    : null;

  // Actualizar cliente_edit_row con nuevo id_bano
  storeValue(
    "cliente_edit_row",
    { ...(appsmith.store.cliente_edit_row || {}), id_bano: idSeleccionado },
    true
  );

  if (!idSeleccionado) {
    storeValue("bano_nuevo_obj", null, true);
    storeValue("cambio_bano", false, true);
    storeValue("mensaje_cambio_bano", "No hay cambio de baño.", true);
    return;
  }

  // Buscar datos del baño nuevo en inventario
  const inv = Array.isArray(GetInventario.data) ? GetInventario.data : [];
  const banoNuevoData = inv.find(b => {
    const id = b && b.id_bano ? String(b.id_bano).trim() : "";
    return id && id === idSeleccionado;
  }) || null;

  storeValue("bano_nuevo_obj", banoNuevoData ? {
    id_bano: idSeleccionado,
    tipo_bano: banoNuevoData.tipo_bano ? String(banoNuevoData.tipo_bano).trim() : null,
    estatus_bano: "Colocado con cliente",
    fecha_compra: banoNuevoData.fecha_compra ? String(banoNuevoData.fecha_compra).trim() : null
  } : null, true);

  // Detectar cambio vs original
  const idOriginal = appsmith.store.bano_original_pedido || null;
  const huboCambio = idOriginal && idSeleccionado ? idSeleccionado !== idOriginal : false;

  storeValue("cambio_bano", huboCambio, true);
  storeValue(
    "mensaje_cambio_bano",
    huboCambio
      ? `Se cambiará el baño: ${idOriginal} → ${idSeleccionado}`
      : "No hay cambio de baño.",
    true
  );
})()
}}

sourceData:
{{  
(() => {  
  var inv = GetInventario.data || [];  

  // Mapea todas las opciones sin filtrar por estatus  
  var opts = inv.map(function(b) {  
    var id = (b && b.id_bano) ? String(b.id_bano) : "";  
    return { label: id, value: id };  
  });

// Baño actual del pedido en edición
var actual = appsmith.store && appsmith.store.cliente_edit_row && appsmith.store.cliente_edit_row.id_bano
? String(appsmith.store.cliente_edit_row.id_bano).trim()
: "";

// Si el actual no está en disponibles, lo anteponemos
if (actual && !opts.some(function(o){ return o.value === actual; })) {
var found = inv.find(function(b){
var id = (b && b.id_bano) ? String(b.id_bano) : "";
return id === actual;
});
opts.unshift({
label: found ? (actual + " (actual)") : (actual + " (no disponible)"),
value: actual
});
}

return opts;
})()
}}
